import{_ as e,o,c as t,Q as s}from"./chunks/framework.4a66d6f9.js";const m=JSON.parse('{"title":"Windows下Docker Desktop安装","description":"","frontmatter":{},"headers":[],"relativePath":"actions/env/Windows下Docker Desktop安装.md","filePath":"actions/env/Windows下Docker Desktop安装.md","lastUpdated":1704522520000}'),i={name:"actions/env/Windows下Docker Desktop安装.md"},l=s('<h1 id="windows下docker-desktop安装" tabindex="-1">Windows下Docker Desktop安装 <a class="header-anchor" href="#windows下docker-desktop安装" aria-label="Permalink to &quot;Windows下Docker Desktop安装&quot;">​</a></h1><ol><li><p>官网下载安装包Docker Desktop Installer.exe</p></li><li><p>运行安装并重启</p></li><li><p>提示WSL2的linux内核安装不完整,点击链接跟随教程操作</p><p><img src="https://storyxc.com/images/blog//image-20210427020640967.png" alt="image-20210427020640967"></p></li><li><p>执行指引中的命令</p><ul><li>步骤 1 - 启用适用于 Linux 的 Windows 子系统<code>dism.exe /online /enable-feature /featurename:Microsoft-Windows-Subsystem-Linux /all /norestart</code></li><li>步骤 2 - 检查运行 WSL 2 的要求，不同架构的系统版本要求不同</li><li>步骤 3 - 启用虚拟机功能，前提是开启虚拟化，如何开启虚拟化不再赘述<code>dism.exe /online /enable-feature /featurename:VirtualMachinePlatform /all /norestart</code></li><li>步骤 4 - 下载 Linux 内核更新包，地址：<a href="https://wslstorestorage.blob.core.windows.net/wslblob/wsl_update_x64.msi" target="_blank" rel="noreferrer">https://wslstorestorage.blob.core.windows.net/wslblob/wsl_update_x64.msi</a></li><li>步骤 5 - 将 WSL 2 设置为默认版本<code>wsl --set-default-version 2</code></li><li>步骤 6 - 安装所选的 Linux 分发，官方提供的方案是在微软商店中下载，因为网络原因很难实现，采取手动下载或命令行下载，参考地址<code>https://docs.microsoft.com/zh-cn/windows/wsl/install-manual</code>，下载完成后cd到下载的目录，执行<code>Add-AppxPackage .\\filename</code>即可 <ul><li>查看所有安装的分发版本<code>wsl --list --all</code></li><li>卸载指定的分发版本<code>wsl --unregister &lt;DistributionName&gt;</code></li></ul></li><li>打开已安装的分发版本，在安装后会提示创建linux账户和密码</li></ul></li></ol>',2),a=[l];function n(r,c,d,p,_,u){return o(),t("div",null,a)}const k=e(i,[["render",n]]);export{m as __pageData,k as default};
